// src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div>Loading dashboard data...</div>;

  const donutOptions = {
    cutout: "70%",
    plugins: {
      tooltip: { enabled: true },
      legend: { display: false },
    },
  };

  const renderSmallDonut = (label, value, color) => ({
    data: {
      labels: [label, ""],
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  const pieData = {
    labels: ["Free", "Occupied"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4CAF50", "#F44336"],
        borderWidth: 0,
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
      },
    ],
  };

  return (
    <div className="dashboard-container">
      <div className="left-section">
        <div className="donut-main">
          <Doughnut data={pieData} options={donutOptions} />
          <div className="donut-center-text">
            <strong>{stats.pieChart.free}</strong> Free<br />
            <strong>{stats.pieChart.occupied}</strong> Occupied
          </div>
        </div>

        <div className="small-donuts">
          <div className="small-donut">
            <Doughnut data={renderSmallDonut("Projectors", stats.resources.projectorRooms, "#ff9800").data} options={donutOptions} />
            <div className="donut-center-text">{stats.resources.projectorRooms}</div>
          </div>
          <div className="small-donut">
            <Doughnut data={renderSmallDonut("Free Labs", stats.resources.labs, "#9c27b0").data} options={donutOptions} />
            <div className="donut-center-text">{stats.resources.labs}</div>
          </div>
          <div className="small-donut">
            <Doughnut data={renderSmallDonut("Free Rooms", stats.resources.classrooms, "#3f51b5").data} options={donutOptions} />
            <div className="donut-center-text">{stats.resources.classrooms}</div>
          </div>
          <div className="small-donut">
            <Doughnut data={renderSmallDonut("Not Occupied", stats.resources.totalRooms - stats.pieChart.occupied, "#009688").data} options={donutOptions} />
            <div className="donut-center-text">{stats.resources.totalRooms - stats.pieChart.occupied}</div>
          </div>
        </div>
      </div>

      <div className="right-section">
        <h2>Free Rooms per Weekday</h2>
        <Bar data={barData} options={{ responsive: true, plugins: { legend: { display: false } } }} />
      </div>
      <div>
        <h2>Resource Summary</h2>
        <ul className="resource-summary">
          <li><strong>Total Rooms:</strong> {stats.resources.totalRooms}</li>
          <li><strong>Labs:</strong> {stats.resources.labs}</li>
          <li><strong>Projector Rooms:</strong> {stats.resources.projectorRooms}</li>
          <li><strong>Classrooms:</strong> {stats.resources.classrooms}</li>
        </ul>
      </div>
    </div>
  );
};

export default Dashboard;
